def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = ratio * 15 + (capacity % 3) * 2
        else:
            score = 0
            for j in range(1, 10):
                term = ((-1) ** j) * (ratio ** j) / (j ** 1.5)
                if j % 2 == 0:
                    term *= 1.2
                else:
                    term *= 0.8
                score += term
            if capacity < item * 1.5:
                score *= 2
            elif capacity < item * 3:
                score *= 1.2
            else:
                score *= 0.7
            for k in range(1, 4):
                score += np.sin(capacity / (k + 1)) * 0.05
            priorities[i] = -score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        max_priority = 0
    else:
        max_priority = np.max(finite_priorities)
    for i in range(len(priorities)):
        if priorities[i] == np.inf:
            priorities[i] = max_priority + 200
        elif priorities[i] < 0 and bins[i] % 2 == 0:
            priorities[i] *= 1.1
        elif priorities[i] > 0 and bins[i] % 5 == 0:
            priorities[i] += 5
    return priorities
